// Package upgradechain provides a deterministic, pre-generated C-Chain
// history crossing every scheduled network upgrade, for tests that need
// realistic synchronous blocks and state; e.g. tests of the coreth-to-SAE
// transition.
//
// The fixture is generated by TestFixtureUpToDate: a full coreth VM
// activates each upgrade at a distinct timestamp and accepts at least one
// block per upgrade exercising an observable change of that upgrade. The
// generator then dumps every accepted block and the VM's entire database.
//
//go:generate go test -run TestFixtureUpToDate -update .
package upgradechain

import (
	"encoding/json"

	"github.com/ava-labs/libevm/common"
	"github.com/ava-labs/libevm/common/hexutil"

	"github.com/ava-labs/avalanchego/ids"
	"github.com/ava-labs/avalanchego/upgrade"
)

// A Fixture is a complete, deterministic C-Chain history.
type Fixture struct {
	// Genesis is the JSON-encoded core.Genesis passed to the VM's
	// Initialize method.
	Genesis json.RawMessage `json:"genesis"`
	// Upgrades is the [upgrade.Config] the chain was generated with.
	// Upgrades after the tip's (Helicon onwards) are unscheduled.
	Upgrades upgrade.Config `json:"upgrades"`
	// ANTAssetID is the Avalanche-native-token asset ID imported in block 3
	// and moved by the fixture's nativeAssetCall transactions.
	ANTAssetID ids.ID `json:"antAssetID"`
	// Counter is the address of the fixture's counter contract, deployed in
	// block 1. A transaction (or eth_call) with empty call data increments
	// its storage slot 0; non-empty call data returns the slot's value as a
	// 32-byte word.
	Counter common.Address `json:"counter"`
	// Blocks holds every accepted block, in height order, starting at
	// height 1.
	Blocks []Block `json:"blocks"`
	// Database holds every key-value pair of the VM's database after all
	// Blocks were accepted, keyed by the hex-encoded key. Written verbatim
	// to an empty database, they recreate the state a coreth node would
	// hand to its successor VM.
	Database map[string]hexutil.Bytes `json:"database"`
}

// A Block is a single accepted block of the fixture chain.
type Block struct {
	// Fork names the network upgrade whose rules the block was built under.
	Fork string `json:"fork"`
	// Note describes what the block exercises.
	Note   string      `json:"note"`
	Number uint64      `json:"number"`
	Hash   common.Hash `json:"hash"`
	// Time is the block's timestamp in Unix seconds.
	Time uint64 `json:"time"`
	// RLP is the canonical encoding of the full block. Decoding it requires
	// the coreth libevm extras to be registered; see customtypes.Register.
	RLP hexutil.Bytes `json:"rlp"`
	// State holds the watched accounts' post-execution state as coreth
	// itself computed it, for asserting historical RPC results against.
	State map[common.Address]AccountState `json:"state"`
	// Counter is the value of the counter contract's storage slot 0 after
	// this block executed.
	Counter uint64 `json:"counterValue"`
}

// AccountState is the post-execution balance and nonce of an account.
type AccountState struct {
	Balance *hexutil.Big `json:"balance"`
	Nonce   uint64       `json:"nonce"`
	// ANTBalance is the account's multicoin balance of [Fixture.ANTAssetID].
	ANTBalance *hexutil.Big `json:"antBalance"`
}

// Heights ([Block.Number]) of fixture blocks that consuming tests single
// out. The generator asserts them, so they cannot silently drift.
var (
	// NativeAssetCallBlocks carry a functional nativeAssetCall, whose nested
	// EVM call makes tracing fail with [NativeAssetCallTraceError] — in
	// coreth and in any replaying VM.
	NativeAssetCallBlocks = []uint64{4, 8}

	// DeprecatedNativeAssetCallBlock's nativeAssetCall ran while the
	// precompile was deprecated, giving the fixture's only failed receipt.
	DeprecatedNativeAssetCallBlock uint64 = 7

	// SendWarpMessageBlock's sendWarpMessage logs the warp precompile's
	// SendWarpMessage event.
	SendWarpMessageBlock uint64 = 12
)

// NativeAssetCallTraceError is the exact error from coreth's debug_trace*
// endpoints on [NativeAssetCallBlocks].
const NativeAssetCallTraceError = "incorrect number of top-level calls"

// Parse decodes a JSON-encoded fixture, as committed at
// vms/saevm/cchain/testdata/upgradechain_fixture.json.
func Parse(data []byte) (*Fixture, error) {
	f := new(Fixture)
	if err := json.Unmarshal(data, f); err != nil {
		return nil, err
	}
	return f, nil
}
